2	
3	export function createProject({ name, description = '', ownerId }) {
4	  if (!name?.trim()) {
5	    throw Object.assign(new Error('Project name is required'), { status: 400 });
6	  }
7	  if (!ownerId) {
8	    throw Object.assign(new Error('Owner ID is required'), { status: 400 });
9	  }
10	
11	  const projects = getCollection('projects');
12	  const id = generateId('project');
13	  const project = {
14	    id,
15	    name: name.trim(),
16	    description,
17	    ownerId,
18	    members: [ownerId],
19	    status: 'active',
20	    createdAt: new Date().toISOString(),
21	    updatedAt: new Date().toISOString(),
22	  };
23	
24	  projects.set(id, project);
25	  return project;
26	}
27	
28	export function getProject(id) {
29	  const project = getCollection('projects').get(id);
30	  if (!project) {
31	    throw Object.assign(new Error(`Project ${id} not found`), { status: 404 });
32	  }
33	  return project;
34	}
35	
36	export function listProjects({ ownerId, status, page = 1, limit = 20 } = {}) {
37	  let results = [...getCollection('projects').values()];
38	
39	  if (ownerId) results = results.filter(p => p.ownerId === ownerId);
40	  if (status) results = results.filter(p => p.status === status);
41	
42	  const total = results.length;
43	  const start = (page - 1) * limit;
44	  return { data: results.slice(start, start + limit), total, page, limit };
45	}
46	
47	export function updateProject(id, updates) {
48	  const project = getProject(id);
49	  const allowed = ['name', 'description', 'status'];
50	  for (const key of allowed) {
51	    if (updates[key] !== undefined) {
52	      project[key] = updates[key];
53	    }
54	  }
55	  project.updatedAt = new Date().toISOString();
56	  return project;
57	}
58	
59	export function deleteProject(id) {
60	  const project = getProject(id);
61	  getCollection('projects').delete(id);
62	
63	  const tasks = getCollection('tasks');
64	  for (const [taskId, task] of tasks) {
65	    if (task.projectId === id) tasks.delete(taskId);
66	  }
67	
68	  return project;
69	}
70	
71	export function addMember(projectId, userId) {
72	  const project = getProject(projectId);
73	  if (!project.members.includes(userId)) {
74	    project.members.push(userId);
75	    project.updatedAt = new Date().toISOString();
76	  }
77	  return project;
78	}
79	"}
