23	app.use(errorHandler);
24	
25	if (process.env.NODE_ENV !== 'test') {
26	  app.listen(PORT, () => {
27	    console.log(`TaskFlow API listening on port ${PORT}`);
28	  });
29	}
30	
31	export default app;
32	"}
{"tool_use_id": "toolu_01Ugmqv26EsNJNvta5tozv9f", "type": "tool_result", "content": "1	import { Router } from 'express';
2	import { createProject, getProject, listProjects, updateProject, deleteProject, addMember } from '../models/project.js';
3	
4	const router = Router();
5	
6	router.post('/', (req, res, next) => {
7	  try {
8	    const project = createProject(req.body);
9	    res.status(201).json(project);
10	  } catch (err) { next(err); }
11	});
12	
13	router.get('/', (req, res) => {
14	  const { ownerId, status, page, limit } = req.query;
15	  const result = listProjects({
16	    ownerId, status,
17	    page: page ? parseInt(page) : 1,
18	    limit: limit ? Math.min(parseInt(limit), 100) : 20,
19	  });
20	  res.json(result);
21	});
22	
23	router.get('/:id', (req, res, next) => {
24	  try {
25	    res.json(getProject(req.params.id));
26	  } catch (err) { next(err); }
27	});
28	
29	router.patch('/:id', (req, res, next) => {
30	  try {
31	    res.json(updateProject(req.params.id, req.body));
32	  } catch (err) { next(err); }
33	});
34	
35	router.delete('/:id', (req, res, next) => {
36	  try {
37	    deleteProject(req.params.id);
38	    res.status(204).end();
39	  } catch (err) { next(err); }
40	});
41	
42	router.post('/:id/members', (req, res, next) => {
43	  try {
44	    const { userId } = req.body;
45	    if (!userId) return res.status(400).json({ error: 'userId is required' });
46	    res.json(addMember(req.params.id, userId));
47	  } catch (err) { next(err); }
48	});
49	
50	export default router;
51	"}
