      since,
      until,
      page: page ? parseInt(page) : 1,
      limit: limit ? Math.min(parseInt(limit), 100) : 20,
    });
    res.json(result);
  } catch (err) { next(err); }
}

// GET /api/tasks/:id/activity - activity for a specific task
export function taskActivityHandler(req, res, next) {
  try {
    const task = getTask(req.params.id); // validates task exists
    const { type, since, until, page, limit } = req.query;
    const result = listActivities({
      resourceId: req.params.id,
      resourceType: 'task',
      type,
      since,
      until,
      page: page ? parseInt(page) : 1,
      limit: limit ? Math.min(parseInt(limit), 100) : 20,
    });
    res.json(result);
  } catch (err) { next(err); }
}

export default router;
