  const task = getTask(id);

  if (updates.status && !VALID_STATUSES.includes(updates.status)) {
    throw Object.assign(new Error(`Invalid status: ${updates.status}`), { status: 400 });
  }
  if (updates.priority && !VALID_PRIORITIES.includes(updates.priority)) {
    throw Object.assign(new Error(`Invalid priority: ${updates.priority}`), { status: 400 });
  }

  const allowed = ['title', 'description', 'assigneeId', 'status', 'priority', 'tags'];
  const changes = {};
  const oldStatus = task.status;
  for (const key of allowed) {
    if (updates[key] !== undefined) {
      const from = Array.isArray(task[key]) ? [...task[key]] : task[key];
      const to = Array.isArray(updates[key]) ? [...updates[key]] : updates[key];
      if (JSON.stringify(from) !== JSON.stringify(to)) {
        changes[key] = { from, to };
      }
      task[key] = updates[key];
    }
  }

  task.updatedAt = new Date().toISOString();

  if (Object.keys(changes).length > 0) {
    recordActivity({
      type: 'task.updated',
      actor: null,
      projectId: task.projectId,
      resourceType: 'task',
      resourceId: id,
      changes,
