describe('Activity Model', () => {
  beforeEach(() => { resetStore(); });

  describe('recordActivity', () => {
    it('should record an activity entry', () => {
      const entry = recordActivity({
        type: 'task.created',
        actor: 'user_1',
        projectId: 'project_1',
        resourceType: 'task',
        resourceId: 'task_1',
      });

      assert.ok(entry.id.startsWith('activity_'));
      assert.equal(entry.type, 'task.created');
      assert.equal(entry.actor, 'user_1');
      assert.equal(entry.projectId, 'project_1');
      assert.equal(entry.resourceType, 'task');
      assert.equal(entry.resourceId, 'task_1');
      assert.equal(entry.changes, null);
      assert.ok(entry.timestamp);
    });

    it('should record changes when provided', () => {
      const changes = { status: { from: 'todo', to: 'in_progress' } };
      const entry = recordActivity({
        type: 'task.updated',
        actor: 'user_1',
        projectId: 'project_1',
        resourceType: 'task',
        resourceId: 'task_1',
        changes,
      });

      assert.deepEqual(entry.changes, changes);
    });

    it('should reject invalid activity types', () => {
      assert.throws(() => {
        recordActivity({
          type: 'invalid.type',
          actor: 'user_1',
          projectId: 'project_1',
          resourceType: 'task',
          resourceId: 'task_1',
        });
      }, { message: /Invalid activity type/ });
    });

    it('should set actor to null when not provided', () => {
      const entry = recordActivity({
        type: 'task.created',
        projectId: 'project_1',
        resourceType: 'task',
        resourceId: 'task_1',
      });
      assert.equal(entry.actor, null);
    });
  });

  describe('ring buffer eviction', () => {
    it('should evict oldest entries when exceeding 1000 per project', () => {
      // Create 1005 activities for the same project
      for (let i = 0; i < 1005; i++) {
        recordActivity({
          type: 'task.created',
          actor: 'user_1',
          projectId: 'project_1',
          resourceType: 'task',
          resourceId: `task_${i}`,
        });
      }

      const result = listActivities({ projectId: 'project_1', limit: 100 });
      assert.equal(result.total, 1000);
    });

    it('should not evict entries from different projects', () => {
      // Create 1005 activities for project_1
      for (let i = 0; i < 1005; i++) {
        recordActivity({
          type: 'task.created',
          actor: 'user_1',
          projectId: 'project_1',
          resourceType: 'task',
          resourceId: `task_${i}`,
        });
      }

      // Create 5 activities for project_2
      for (let i = 0; i < 5; i++) {
        recordActivity({
          type: 'task.created',
          actor: 'user_1',
          projectId: 'project_2',
          resourceType: 'task',
          resourceId: `task_${i}`,
        });
      }

      const result1 = listActivities({ projectId: 'project_1', limit: 100 });
      assert.equal(result1.total, 1000);

      const result2 = listActivities({ projectId: 'project_2', limit: 100 });
      assert.equal(result2.total, 5);
    });

    it('should evict the oldest entries first', () => {
      for (let i = 0; i < 1002; i++) {
        recordActivity({
          type: 'task.created',
          actor: 'user_1',
          projectId: 'project_1',
          resourceType: 'task',
          resourceId: `task_${i}`,
        });
      }

      // The first 2 entries (task_0, task_1) should be evicted
      const result = listActivities({ projectId: 'project_1', limit: 1000 });
      const resourceIds = result.data.map(a => a.resourceId);
      assert.ok(!resourceIds.includes('task_0'));
      assert.ok(!resourceIds.includes('task_1'));
      assert.ok(resourceIds.includes('task_2'));
      assert.ok(resourceIds.includes('task_1001'));
    });
  });

  describe('listActivities', () => {
    it('should return empty list when no activities', () => {
      const result = listActivities();
      assert.deepEqual(result, { data: [], total: 0, page: 1, limit: 20 });
    });

    it('should filter by projectId', () => {
      recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.created', projectId: 'project_2', resourceType: 'task', resourceId: 'task_2' });

      const result = listActivities({ projectId: 'project_1' });
      assert.equal(result.total, 1);
      assert.equal(result.data[0].projectId, 'project_1');
    });

    it('should filter by type', () => {
      recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.updated', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.deleted', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });

      const result = listActivities({ type: 'task.updated' });
      assert.equal(result.total, 1);
      assert.equal(result.data[0].type, 'task.updated');
    });

    it('should filter by actor', () => {
      recordActivity({ type: 'task.created', actor: 'user_1', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.created', actor: 'user_2', projectId: 'project_1', resourceType: 'task', resourceId: 'task_2' });

      const result = listActivities({ actor: 'user_1' });
      assert.equal(result.total, 1);
      assert.equal(result.data[0].actor, 'user_1');
    });

    it('should filter by date range (since/until)', () => {
      const early = recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      const late = recordActivity({ type: 'task.updated', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });

      // since: filter entries >= timestamp
      const sinceResult = listActivities({ since: late.timestamp });
      assert.ok(sinceResult.total >= 1);
      for (const entry of sinceResult.data) {
        assert.ok(entry.timestamp >= late.timestamp);
      }
    });

    it('should paginate results', () => {
      for (let i = 0; i < 5; i++) {
        recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: `task_${i}` });
      }

      const page1 = listActivities({ page: 1, limit: 2 });
      assert.equal(page1.data.length, 2);
      assert.equal(page1.total, 5);
      assert.equal(page1.page, 1);
      assert.equal(page1.limit, 2);

      const page2 = listActivities({ page: 2, limit: 2 });
      assert.equal(page2.data.length, 2);

      const page3 = listActivities({ page: 3, limit: 2 });
      assert.equal(page3.data.length, 1);
    });

    it('should return results sorted newest first', () => {
      recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.updated', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.deleted', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });

      const result = listActivities();
      assert.equal(result.data[0].type, 'task.deleted');
      assert.equal(result.data[2].type, 'task.created');
    });

    it('should return empty data for out-of-range pages', () => {
      recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });

      const result = listActivities({ page: 99 });
      assert.equal(result.data.length, 0);
      assert.equal(result.total, 1);
    });
  });

  describe('getActivityById', () => {
    it('should return activity by ID', () => {
      const entry = recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      const found = getActivityById(entry.id);
      assert.equal(found.id, entry.id);
    });

    it('should throw 404 for non-existent activity', () => {
      assert.throws(() => {
        getActivityById('activity_999');
      }, { message: /not found/ });
    });
  });
});

