{"type": "tool_use", "id": "toolu_01KJxSo5sYKBJTRzKEe3QbTj", "name": "Write", "input": {"file_path": "/private/tmp/js-bench-workspace/src/models/activity.js", "content": "import { generateId, getCollection } from './store.js';

const MAX_PER_PROJECT = 1000;

const VALID_TYPES = [
  'project.created',
  'project.updated',
  'project.deleted',
  'project.member_added',
  'task.created',
  'task.updated',
  'task.deleted',
  'task.status_changed',
];

export function recordActivity({ type, actor, projectId, resourceType, resourceId, changes = null }) {
  if (!VALID_TYPES.includes(type)) {
    throw Object.assign(new Error(`Invalid activity type: ${type}`), { status: 400 });
  }

  const activities = getCollection('activities');
  const id = generateId('activity');
  const entry = {
    id,
    type,
    actor: actor || null,
    projectId,
    resourceType,
    resourceId,
    changes,
    timestamp: new Date().toISOString(),
  };

  activities.set(id, entry);

  // Ring buffer eviction: cap at MAX_PER_PROJECT per project
  const projectEntries = [];
  for (const [key, val] of activities) {
    if (val.projectId === projectId) {
      projectEntries.push(key);
    }
  }
  if (projectEntries.length > MAX_PER_PROJECT) {
    // projectEntries are in insertion order (Map preserves it), remove oldest
    const toRemove = projectEntries.length - MAX_PER_PROJECT;
    for (let i = 0; i < toRemove; i++) {
      activities.delete(projectEntries[i]);
    }
  }

  return entry;
}

export function listActivities({ projectId, type, actor, resourceType, resourceId, since, until, page = 1, limit = 20 } = {}) {
  let results = [...getCollection('activities').values()];

  if (projectId) results = results.filter(a => a.projectId === projectId);
  if (type) results = results.filter(a => a.type === type);
  if (actor) results = results.filter(a => a.actor === actor);
  if (resourceType) results = results.filter(a => a.resourceType === resourceType);
  if (resourceId) results = results.filter(a => a.resourceId === resourceId);
  if (since) results = results.filter(a => a.timestamp >= since);
  if (until) results = results.filter(a => a.timestamp <= until);

  // Sort newest first
  results.sort((a, b) => b.timestamp.localeCompare(a.timestamp));

  const total = results.length;
  const start = (page - 1) * limit;
  return { data: results.slice(start, start + limit), total, page, limit };
}

export function getActivityById(id) {
  const activity = getCollection('activities').get(id);
  if (!activity) {
    throw Object.assign(new Error(`Activity ${id} not found`), { status: 404 });
  }
  return activity;
}
