      recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });

      const result = listActivities({ page: 99 });
      assert.equal(result.data.length, 0);
      assert.equal(result.total, 1);
    });
  });

  describe('getActivityById', () => {
    it('should return activity by ID', () => {
      const entry = recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
