describe('Activity API Endpoints', () => {
  let server, baseUrl;

  beforeEach(async () => {
    resetStore();
    server = app.listen(0);
    const port = server.address().port;
    baseUrl = `http://localhost:${port}`;
  });

  afterEach(() => server.close());

  describe('GET /api/activity', () => {
    it('should return empty list initially', async () => {
      const res = await fetch(`${baseUrl}/api/activity`);
      const body = await res.json();
      assert.equal(res.status, 200);
      assert.deepEqual(body.data, []);
      assert.equal(body.total, 0);
    });

    it('should return activities after mutations', async () => {
      const user = await createTestUser(baseUrl);
      await createTestProject(baseUrl, user.id);

      const res = await fetch(`${baseUrl}/api/activity`);
      const body = await res.json();
      assert.ok(body.total >= 1);
    });

    it('should filter by projectId', async () => {
      const user = await createTestUser(baseUrl);
      const p1 = await createTestProject(baseUrl, user.id, { name: 'Project 1' });
      const p2 = await createTestProject(baseUrl, user.id, { name: 'Project 2' });

      const res = await fetch(`${baseUrl}/api/activity?projectId=${p1.id}`);
      const body = await res.json();
      for (const entry of body.data) {
        assert.equal(entry.projectId, p1.id);
      }
    });

    it('should filter by type', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);
      await createTestTask(baseUrl, project.id);

      const res = await fetch(`${baseUrl}/api/activity?type=task.created`);
      const body = await res.json();
      for (const entry of body.data) {
        assert.equal(entry.type, 'task.created');
      }
    });

    it('should support pagination', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);
      for (let i = 0; i < 5; i++) {
        await createTestTask(baseUrl, project.id, { title: `Task ${i}` });
      }

      const res = await fetch(`${baseUrl}/api/activity?page=1&limit=2`);
      const body = await res.json();
      assert.equal(body.data.length, 2);
      assert.equal(body.page, 1);
      assert.equal(body.limit, 2);
      assert.ok(body.total > 2);
    });

    it('should filter by since parameter', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);

      const beforeTask = new Date().toISOString();
      await createTestTask(baseUrl, project.id);

      const res = await fetch(`${baseUrl}/api/activity?since=${beforeTask}&type=task.created`);
      const body = await res.json();
      assert.ok(body.total >= 1);
    });
  });

  describe('GET /api/projects/:id/activity', () => {
    it('should return activities for a specific project', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);
      await createTestTask(baseUrl, project.id);

      const res = await fetch(`${baseUrl}/api/projects/${project.id}/activity`);
      const body = await res.json();
      assert.ok(body.total >= 2); // project.created + task.created
      for (const entry of body.data) {
        assert.equal(entry.projectId, project.id);
      }
    });

    it('should return 404 for non-existent project', async () => {
      const res = await fetch(`${baseUrl}/api/projects/project_999/activity`);
      assert.equal(res.status, 404);
    });

    it('should support filtering by type', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);
      await createTestTask(baseUrl, project.id);

      const res = await fetch(`${baseUrl}/api/projects/${project.id}/activity?type=task.created`);
      const body = await res.json();
      for (const entry of body.data) {
        assert.equal(entry.type, 'task.created');
      }
    });
  });

  describe('GET /api/tasks/:id/activity', () => {
    it('should return activities for a specific task', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);
      const task = await createTestTask(baseUrl, project.id);

      // Update the task
      await fetch(`${baseUrl}/api/tasks/${task.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: 'in_progress' }),
      });

      const res = await fetch(`${baseUrl}/api/tasks/${task.id}/activity`);
      const body = await res.json();
      // task.created + task.updated + task.status_changed
      assert.ok(body.total >= 3);
      for (const entry of body.data) {
        assert.equal(entry.resourceId, task.id);
      }
    });

    it('should return 404 for non-existent task', async () => {
      const res = await fetch(`${baseUrl}/api/tasks/task_999/activity`);
      assert.equal(res.status, 404);
    });
  });

  describe('change tracking through API', () => {
    it('should track project update changes via API', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id, { name: 'Original' });

      await fetch(`${baseUrl}/api/projects/${project.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: 'Updated' }),
      });

      const res = await fetch(`${baseUrl}/api/activity?type=project.updated`);
      const body = await res.json();
      assert.equal(body.total, 1);
      assert.deepEqual(body.data[0].changes.name, { from: 'Original', to: 'Updated' });
    });

    it('should track member addition via API', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);

      await fetch(`${baseUrl}/api/projects/${project.id}/members`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: 'user_99' }),
      });

      const res = await fetch(`${baseUrl}/api/activity?type=project.member_added`);
      const body = await res.json();
      assert.equal(body.total, 1);
    });

    it('should track task deletion and record project.deleted on cascade', async () => {
      const user = await createTestUser(baseUrl);
      const project = await createTestProject(baseUrl, user.id);
      await createTestTask(baseUrl, project.id, { title: 'Task A' });
      await createTestTask(baseUrl, project.id, { title: 'Task B' });

      await fetch(`${baseUrl}/api/projects/${project.id}`, { method: 'DELETE' });

      const taskDeleted = await (await fetch(`${baseUrl}/api/activity?type=task.deleted`)).json();
      const projectDeleted = await (await fetch(`${baseUrl}/api/activity?type=project.deleted`)).json();
      assert.equal(taskDeleted.total, 2);
      assert.equal(projectDeleted.total, 1);
    });
  });
});
