      }

      const result1 = listActivities({ projectId: 'project_1', limit: 100 });
      assert.equal(result1.total, 1000);

      const result2 = listActivities({ projectId: 'project_2', limit: 100 });
      assert.equal(result2.total, 5);
    });

    it('should evict the oldest entries first', () => {
      for (let i = 0; i < 1002; i++) {
        recordActivity({
          type: 'task.created',
          actor: 'user_1',
          projectId: 'project_1',
          resourceType: 'task',
          resourceId: `task_${i}`,
        });
      }

      // The first 2 entries (task_0, task_1) should be evicted
      const result = listActivities({ projectId: 'project_1', limit: 1000 });
      const resourceIds = result.data.map(a => a.resourceId);
      assert.ok(!resourceIds.includes('task_0'));
      assert.ok(!resourceIds.includes('task_1'));
      assert.ok(resourceIds.includes('task_2'));
      assert.ok(resourceIds.includes('task_1001'));
