      const result = listActivities({ projectId: 'project_1' });
      assert.equal(result.total, 1);
      assert.equal(result.data[0].projectId, 'project_1');
    });

    it('should filter by type', () => {
      recordActivity({ type: 'task.created', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.updated', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });
      recordActivity({ type: 'task.deleted', projectId: 'project_1', resourceType: 'task', resourceId: 'task_1' });

