describe('Activity Integration - Model Level', () => {
  beforeEach(() => { resetStore(); });

  it('should record activity when a project is created', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });

    const result = listActivities({ type: 'project.created' });
    assert.equal(result.total, 1);
    assert.equal(result.data[0].resourceId, 'project_1');
    assert.equal(result.data[0].actor, 'user_1');
  });

  it('should record activity when a project is updated', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    updateProject('project_1', { name: 'Updated' });

    const result = listActivities({ type: 'project.updated' });
    assert.equal(result.total, 1);
    assert.deepEqual(result.data[0].changes.name, { from: 'Test', to: 'Updated' });
  });

  it('should not record activity when project update has no changes', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    updateProject('project_1', { name: 'Test' }); // same value

    const result = listActivities({ type: 'project.updated' });
    assert.equal(result.total, 0);
  });

  it('should record activity when a project is deleted', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    deleteProject('project_1');

    const result = listActivities({ type: 'project.deleted' });
    assert.equal(result.total, 1);
    assert.equal(result.data[0].resourceId, 'project_1');
  });

  it('should record activity when a member is added', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    addMember('project_1', 'user_2');

    const result = listActivities({ type: 'project.member_added' });
    assert.equal(result.total, 1);
    assert.deepEqual(result.data[0].changes.members.from, ['user_1']);
    assert.deepEqual(result.data[0].changes.members.to, ['user_1', 'user_2']);
  });

  it('should record activity when a task is created', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    createTask({ title: 'My Task', projectId: 'project_1' });

    const result = listActivities({ type: 'task.created' });
    assert.equal(result.total, 1);
    assert.equal(result.data[0].resourceId, 'task_1');
    assert.equal(result.data[0].projectId, 'project_1');
  });

  it('should record activity when a task is updated with changes', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    createTask({ title: 'My Task', projectId: 'project_1' });
    updateTask('task_1', { title: 'Updated Task', priority: 'high' });

    const result = listActivities({ type: 'task.updated' });
    assert.equal(result.total, 1);
    assert.deepEqual(result.data[0].changes.title, { from: 'My Task', to: 'Updated Task' });
    assert.deepEqual(result.data[0].changes.priority, { from: 'medium', to: 'high' });
  });

  it('should record task.status_changed when status changes', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    createTask({ title: 'My Task', projectId: 'project_1' });
    updateTask('task_1', { status: 'in_progress' });

    const result = listActivities({ type: 'task.status_changed' });
    assert.equal(result.total, 1);
    assert.deepEqual(result.data[0].changes.status, { from: 'todo', to: 'in_progress' });
  });

  it('should record both task.updated and task.status_changed on status change', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    createTask({ title: 'My Task', projectId: 'project_1' });
    updateTask('task_1', { status: 'done' });

    const updated = listActivities({ type: 'task.updated' });
    const statusChanged = listActivities({ type: 'task.status_changed' });
    assert.equal(updated.total, 1);
    assert.equal(statusChanged.total, 1);
  });

  it('should record activity when a task is deleted', () => {
    createUser({ name: 'Alice', email: 'alice@example.com' });
    createProject({ name: 'Test', ownerId: 'user_1' });
    createTask({ title: 'My Task', projectId: 'project_1' });
    deleteTask('task_1');

    const result = listActivities({ type: 'task.deleted' });
